import{_ as t,o,c as r,ak as a,aH as s,aI as n,aJ as i,aK as p,aL as c,aM as h,aN as d,aO as l}from"./chunks/framework.BT3e1GSl.js";const w=JSON.parse('{"title":"Shape your box","description":"","frontmatter":{},"headers":[],"relativePath":"dotpi-box/shape-your-box.md","filePath":"dotpi-box/shape-your-box.md"}'),m={name:"dotpi-box/shape-your-box.md"};function u(f,e,x,_,b,g){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="shape-your-box" tabindex="-1">Shape your box <a class="header-anchor" href="#shape-your-box" aria-label="Permalink to “Shape your box”">​</a></h1><p>If for any reason you would like to modify the project (e.g. different hardware pieces or different needs), you can modify the <a href="https://www.autodesk.com/fr/products/fusion-360/overview" target="_blank" rel="noreferrer">Fusion 360</a> project downloadable at <a href="../assets/modify-the-project/dotpi-box-v99-fusion-project.zip">this link</a>.</p><h2 id="structure-of-the-project" tabindex="-1">Structure of the project <a class="header-anchor" href="#structure-of-the-project" aria-label="Permalink to “Structure of the project”">​</a></h2><p>The project is structured around 6 bodies (corresponding to the 6 faces of the box)</p><p><img src="'+s+'" alt="fusion-bodies"></p><p>And three components: the Raspberry Pi + Amp module, the Visaton SL 87 FE speaker, and the separation body inside the cabinet (component10:1).</p><p><img src="'+n+'" alt="fusion-components"></p><p>You can find all the sketches and extrusions in the timeline at the bottom of the project and modify them as you wish!</p><h2 id="exports" tabindex="-1">Exports <a class="header-anchor" href="#exports" aria-label="Permalink to “Exports”">​</a></h2><p>We will briefly introduce how to retrieve <em>.stl</em> and <em>.svg</em> exports from the bodies of the Fusion project.</p><h3 id="exporting-stls" tabindex="-1">Exporting STLs <a class="header-anchor" href="#exporting-stls" aria-label="Permalink to “Exporting STLs”">​</a></h3><p>If you want to export <em>.stl</em> files in order to 3D print them (or do whatever you want to do with it), simply select <strong>3D print</strong> in Fusion&#39;s file menu.</p><p><img src="'+i+'" alt="3DPrint-menu" width="250px"></p><p>Select the body you want to export (typically body1 or component10:1), select <strong>STL</strong> as format and <strong>Millimeter</strong> as unit type then click OK.</p><p><img src="'+p+'" alt="3DPrint-parameters"></p><h3 id="exporting-dxfs" tabindex="-1">Exporting DXFs <a class="header-anchor" href="#exporting-dxfs" aria-label="Permalink to “Exporting DXFs”">​</a></h3><p>If you want to export <em>.dxf</em> files in order to laser cut faces (or do whatever you want to do with it), right click anywhere in Fusion venue.</p><p>Select <strong>Sketch</strong> in the drop down menu.</p><p><img src="'+c+'" alt="dxf-dropdown-menu-1" width="300px"></p><p>Then select <strong>Project</strong>.</p><p><img src="'+h+'" alt="dxf-dropdown-menu-2" width="300px"></p><p>Select the face you want to project then click OK</p><p><img src="'+d+'" alt="dxf-select-face"></p><p>You will then find the projection in the Sketches menu on the left hand side of the venue. Right click on it and select <strong>Export DXF</strong></p><p><img src="'+l+'" alt="dxf-sketch-menu" width="300px"></p><h2 id="conclusion" tabindex="-1">Conclusion <a class="header-anchor" href="#conclusion" aria-label="Permalink to “Conclusion”">​</a></h2><p>You can now use your own <em>.stl</em> and <em>.dxf</em> files to 3D print and laser cut your customized pieces!</p>',27)])])}const k=t(m,[["render",u]]);export{w as __pageData,k as default};
